import{_ as d,o as e,c as r,a7 as a}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"物资与货币","description":"","frontmatter":{},"headers":[],"relativePath":"items/currency.md","filePath":"zh/items/currency.md","lastUpdated":1775394001000}'),h={name:"items/currency.md"};function o(i,t,n,l,s,b){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="物资与货币" tabindex="-1">物资与货币 <a class="header-anchor" href="#物资与货币" aria-label="Permalink to &quot;物资与货币&quot;">​</a></h1><h2 id="付费货币" tabindex="-1">付费货币 <a class="header-anchor" href="#付费货币" aria-label="Permalink to &quot;付费货币&quot;">​</a></h2><table tabindex="0"><thead><tr><th>货币名称</th><th>用途</th><th>主要获取途径</th></tr></thead><tbody><tr><td>源液 (Silver Prime)</td><td>购买抽卡、通行证、外观和礼盒</td><td>真金白银充值（标准档位：6/30/68/128/198/328/648元等价）</td></tr></tbody></table><h2 id="抽卡货币" tabindex="-1">抽卡货币 <a class="header-anchor" href="#抽卡货币" aria-label="Permalink to &quot;抽卡货币&quot;">​</a></h2><table tabindex="0"><thead><tr><th>货币名称</th><th>用途</th><th>主要获取途径</th></tr></thead><tbody><tr><td>银芯 (Silver Core)</td><td>主要免费高级货币，兑换流明之芯和无垢之芯；恢复墨诺芬(50银芯=120墨诺芬)</td><td>每日任务、主线评分(100/关)、主线成就、手册、幻梦深潜、活动奖励、通行证、兑换码、地图探索拾取</td></tr><tr><td>流明之芯 (Lumen Core)</td><td>限定池抽卡道具，1个=1抽</td><td>银芯兑换、活动奖励、通行证（获取途径少于无垢之芯，应优先兑换）</td></tr><tr><td>无垢之芯 (Pure Core)</td><td>常驻池/命轮池抽卡道具，1个=1抽</td><td>银芯兑换、活动奖励、角色首次升格、纪行免费轨道(40个)、章节首通</td></tr></tbody></table><h2 id="兑换货币" tabindex="-1">兑换货币 <a class="header-anchor" href="#兑换货币" aria-label="Permalink to &quot;兑换货币&quot;">​</a></h2><table tabindex="0"><thead><tr><th>货币名称</th><th>用途</th><th>主要获取途径</th></tr></thead><tbody><tr><td>蔷薇金券 (Rose Scrip)</td><td>蔷薇金券商店、教化唤醒体、炼金、素材合成、命轮叠加、密契誊抄(7500/次)</td><td>主线首次通关、融蚀之墟、外勤代理、课程、拆解命轮(蓝=1000,紫=4000)</td></tr><tr><td>沉淀币 (Sediment Currency)</td><td>沉淀商店：密契(猩红之拥)、追念羽笔(80沉淀=10笔/周)、原初灵核(25碎片=1核,3次/月)</td><td>抽卡(唤醒)副产物</td></tr><tr><td>调查徽章 (Investigation Badge)</td><td>调查商店：追念羽笔(800徽章=5笔/周)</td><td>主线三星通关、秘术统御、灵魂潜行三星、真实掌握(1000)、个人成就(300/个)</td></tr><tr><td>无光币 (Lightless Currency)</td><td>无光商店：密契(远方的欢宴)、追念羽笔(800=5/周)</td><td>无光秘境、界域异效区</td></tr><tr><td>融蚀之珠 (D-Jewels)</td><td>深潜商店：追念羽笔(800=5/周)、碎裂余梦(100/周)、群星余梦(25/周)</td><td>幻梦深潜(三级=500,疯狂=900)、外勤代理(每日结算)。公式：(幻梦等级+2)x100</td></tr><tr><td>相位币 (Phase Coin)</td><td>相位商店：密契(猩红之悸)、追念羽笔(800=5/周)</td><td>相位对弈(PVP)</td></tr></tbody></table><h2 id="体力" tabindex="-1">体力 <a class="header-anchor" href="#体力" aria-label="Permalink to &quot;体力&quot;">​</a></h2><table tabindex="0"><thead><tr><th>货币名称</th><th>用途</th><th>主要获取途径</th></tr></thead><tbody><tr><td>墨诺芬 (Menophine)</td><td>体力/行动力资源，进入幕间演习消耗</td><td>自然恢复、银芯兑换(50银芯=120墨诺芬)、道具/礼盒</td></tr></tbody></table><h2 id="弥萨格商店" tabindex="-1">弥萨格商店 <a class="header-anchor" href="#弥萨格商店" aria-label="Permalink to &quot;弥萨格商店&quot;">​</a></h2><p>弥萨格商店是游戏内的商店系统，可使用各类货币兑换道具。</p><table tabindex="0"><thead><tr><th>商店类别</th><th>货币</th><th>可兑换内容</th></tr></thead><tbody><tr><td>蔷薇金券商店</td><td>蔷薇金券</td><td>密契(荒原狼)、教化素材、各类培养材料</td></tr><tr><td>沉淀商店</td><td>沉淀币</td><td>密契(猩红之拥)、追念羽笔、原初灵核碎片</td></tr><tr><td>调查商店</td><td>调查徽章</td><td>追念羽笔、密契(猩红之悸)</td></tr><tr><td>无光商店</td><td>无光币</td><td>密契(远方的欢宴)、追念羽笔</td></tr><tr><td>深潜商店</td><td>融蚀之珠</td><td>密契(诅咒兔)、追念羽笔、碎裂余梦、群星余梦</td></tr><tr><td>相位商店</td><td>相位币</td><td>密契(猩红之悸)、追念羽笔</td></tr></tbody></table>',12)])])}const m=d(h,[["render",o]]);export{u as __pageData,m as default};
